#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <stdint.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int *arr = (int*)malloc(1 << N * sizeof(int));
        for (int i = 0; i < (1 << N); i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, (1 << N), sizeof(int), compare);
        int *ans = (int*)malloc(N * sizeof(int));
        ans[0] = arr[1];
        for (int i = 1; i < N; i++) {
            ans[i] = arr[(1 << i)] - arr[(1 << (i - 1))];
        }
        qsort(ans, N, sizeof(int), compare);
        for (int i = 0; i < N; i++) {
            printf("%d ", ans[i]);
        }
        printf("\n");
        free(arr);
        free(ans);
    }
    return 0;
}

