import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[1 << N];
            for (int i = 0; i < (1 << N); i++) {
                arr[i] = sc.nextInt();
            }
            Arrays.sort(arr);
            int[] ans = new int[N];
            ans[0] = arr[1];
            for (int i = 1; i < N; i++) {
                ans[i] = arr[(1 << i)] - arr[(1 << (i - 1))];
            }
            Arrays.sort(ans);
            for (int i = 0; i < N; i++) {
                System.out.print(ans[i] + " ");
            }
            System.out.println();
        }
    }
}

